@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun WorkDialog(
    initial: Work?,
    onDismiss: () -> Unit,
    onConfirm: (title: String, description: String, dueDate: String) -> Unit
) {
    val isEdit = initial != null
    var title by remember { mutableStateOf(initial?.title ?: "") }
    var description by remember { mutableStateOf(initial?.description ?: "") }
    var dueDate by remember { mutableStateOf(initial?.dueDate ?: "") }
    var showDatePicker by remember { mutableStateOf(false) }

    if (showDatePicker) {
        val pickerState = rememberDatePickerState()
        DatePickerDialog(
            onDismissRequest = { showDatePicker = false },
            confirmButton = {
                TextButton(onClick = {
                    val millis = pickerState.selectedDateMillis
                    if (millis != null) {
                        dueDate = Instant.ofEpochMilli(millis)
                            .atOffset(ZoneOffset.UTC).toLocalDate().toString()
                    }
                    showDatePicker = false
                }) { Text("OK") }
            },
            dismissButton = {
                TextButton(onClick = { showDatePicker = false }) { Text("Cancel") }
            }
        ) {
            DatePicker(state = pickerState)
        }
    }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (isEdit) "Edit Assignment" else "Add Assignment") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it },
                    label = { Text("Title *") },
                    singleLine = true,
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = description,
                    onValueChange = { description = it },
                    label = { Text("Description") },
                    singleLine = false,
                    maxLines = 3,
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedButton(
                    onClick = { showDatePicker = true },
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Icon(Icons.Default.DateRange, contentDescription = null,
                        modifier = Modifier.size(16.dp))
                    Spacer(Modifier.width(6.dp))
                    Text(
                        if (dueDate.isBlank()) "Set due date (optional)"
                        else formatWorkDate(dueDate)
                    )
                }
            }
        },
        confirmButton = {
            TextButton(onClick = { onConfirm(title, description, dueDate) }, enabled = title.isNotBlank()) {
                Text(if (isEdit) "Save" else "Add")
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("Cancel") }
        }
    )
}

private fun formatWorkDate(isoDate: String): String = DateUtils.formatDisplayDate(isoDate)

package com.example.combined_schedule.ui.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.combined_schedule.data.AgentRepository
import com.example.combined_schedule.data.AppDatabase
import com.example.combined_schedule.data.ChatMessage
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

class AgentViewModel(app: Application) : AndroidViewModel(app) {

    private val db = AppDatabase.getInstance(app)

    private val _messages = MutableStateFlow<List<ChatMessage>>(emptyList())
    val messages: StateFlow<List<ChatMessage>> = _messages.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    fun send(userText: String) {
        val trimmed = userText.trim()
        if (trimmed.isBlank() || _isLoading.value) return

        val history = _messages.value + ChatMessage("user", trimmed)
        _messages.value = history
        _isLoading.value = true

        viewModelScope.launch {
            val allEntries = db.homeEntryDao().getAllList()
            val allWorks = db.workDao().getAllList()
            val reply = withContext(Dispatchers.IO) {
                try {
                    AgentRepository.chat(history, allEntries, allWorks)
                } catch (e: Exception) {
                    "Error: ${e.message}"
                }
            }
            _messages.value = _messages.value + ChatMessage("assistant", reply)
            _isLoading.value = false
        }
    }

    fun clearHistory() {
        _messages.value = emptyList()
    }

    class Factory(private val app: Application) : ViewModelProvider.Factory {
        @Suppress("UNCHECKED_CAST")
        override fun <T : androidx.lifecycle.ViewModel> create(modelClass: Class<T>): T =
            AgentViewModel(app) as T
    }
}

